// ── Issue (spec §4.1.1) ────────────────────────────────────────────────

/// Normalized issue record from the tracker.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Issue {
    pub id: String,
    pub identifier: String,
    pub title: String,
    #[serde(default)]
    pub description: Option<String>,
    #[serde(default)]
    pub priority: Option<i32>,
    pub state: String,
    #[serde(default)]
    pub branch_name: Option<String>,
